using Godot; public static class FloatingTextSpawner { public static Label Spawn(Node parent,string text,Vector2 globalPosition){ if(parent==null||string.IsNullOrWhiteSpace(text))return null; Label label=new(){Text=text,GlobalPosition=globalPosition}; parent.AddChild(label); Tween t=label.CreateTween(); t.TweenProperty(label,"position:y",label.Position.Y-28f,0.6f); t.Parallel().TweenProperty(label,"modulate:a",0f,0.6f); t.Finished+=label.QueueFree; return label; } }